public class Solution { public bool IsValidSudoku(char[][] board) { int col = 9; int row = 9; for (int i = 0; i < row; i++) { int[] arr = new int[9]; for (int j = 0; j < col; j++) { if (board[i][j] != '.') { int index = board[i][j] - '1'; if (arr[index] == 1) return false; arr[index]++; } } } for (int i = 0; i < col; i++) { int[] arr = new int[9]; for (int j = 0; j < row; j++) { if (board[j][i] != '.') { int index = board[j][i] - '1'; if (arr[index] == 1) return false; arr[index]++; } } } Dictionary<int, int[]> dict = new Dictionary<int, int[]>(); for (int i = 0; i < row; i++) { for (int j = 0; j < col; j++) { int squareIndex = (i / 3) * 3 + j / 3; if (!dict.ContainsKey(squareIndex)) dict[squareIndex] = new int[9]; if (board[i][j] != '.') { int index = board[i][j] - '1'; if (dict[squareIndex][index] == 1) return false; dict[squareIndex][index]++; } } } return true; } }